local TD = TD.td1madao["ydj_dst_td1madao"] local myComponent = Class(function(self, inst)     self.inst = inst     self.taskList = {}     self.accounter = 0 end) function myComponent:common_period(period, fun, taskName, cleanTime, cleanFunction)     local player = self.inst     if not fun then         return     end     if not taskName then         self.accounter = self.accounter + 1         taskName = "task" .. tostring(self.accounter)     end     if not period then         period = 1     end     if not cleanTime then         cleanTime = 15     end     if not cleanFunction then         cleanFunction = TD.empty     end     self:common_clean(taskName)     self:common_clean(taskName .. "cleaner")     self:common_task(cleanTime, function()         cleanFunction()         self:common_clean(taskName)         self:common_clean(taskName .. "cleaner")     end, taskName .. "cleaner")     self.taskList[taskName] = player:DoPeriodicTask(period, fun)     return self.taskList[taskName] end function myComponent:common_task(time, fun, taskName)     local player = self.inst     if not fun then         return     end     if not taskName then         self.accounter = self.accounter + 1         taskName = "task" .. tostring(self.accounter)     end     self:common_clean(taskName)     self.taskList[taskName] = player:DoTaskInTime(time or 1, function()         fun()         self:common_clean(taskName)     end)     return self.taskList[taskName] end function myComponent:common_clean(taskName)     local player = self.inst     if not taskName then         return     end     if player and self.taskList[taskName] then         if self.taskList[taskName].Cancel then             self.taskList[taskName]:Cancel()         end         self.taskList[taskName] = nil     end end function myComponent:common_exist(taskName)     local player = self.inst     if not taskName then         return false     end     return player and self.taskList[taskName] end function myComponent:common_cleanAll(arr)     if not arr then         return     end     for i = 1, #arr do         local name = arr[i]         if name then             self:common_clean(name)         end     end end function myComponent:server_period(period, fun, taskName, cleanTime, cleanFunction)     return self:common_period(period, fun, taskName, cleanTime, cleanFunction) end function myComponent:player_period(period, fun, taskName, cleanTime, cleanFunction)     return self:common_period(period, fun, taskName, cleanTime, cleanFunction) end function myComponent:server_task(time, fun, taskName)     return self:common_task(time, fun, taskName) end function myComponent:player_task(time, fun, taskName)     return self:common_task(time, fun, taskName) end function myComponent:server_clean(taskName)     self:common_clean(taskName) end function myComponent:player_clean(taskName)     self:common_clean(taskName) end function myComponent:server_exist(taskName)     return self:common_exist(taskName) end function myComponent:player_exist(taskName)     return self:common_exist(taskName) end function myComponent:server_cleanAll(arr)     self:common_cleanAll(arr) end function myComponent:player_cleanAll(arr)     self:common_cleanAll(arr) end return myComponent 